<template>
    <div>
        <div class="blogPage">
            <!-- 使用 mavon-editor 组件展示 Markdown 内容 -->
            <mavon-editor style="position:static" :value="markdownContent" :editable="false" :subfield="false"
                :defaultOpen="'preview'" :toolbarsFlag="false" :scrollStyle="true" :ishljs="true" />
        </div>
    </div>
</template>
  
<script>
import axios from 'axios';
import 'mavon-editor/dist/css/index.css';
import { mavonEditor } from 'mavon-editor';
export default {
    components: {
        mavonEditor
    },
    data() {
        return {
            markdownID: null,// 初始化为null
            markdownContent: '',
            BranchParam:''
        };
    },
    created() {
        // 在组件创建时获取路由参数中的id，并赋值给markdownID
        this.markdownID = this.$route.params.tittle;
        this.BranchParam=this.$route.params.BranchParam

        console.log("这是传递过来的参数："+this.markdownID)
    },
    methods: {

    },
    mounted() {
        axios.get("https://gitee.com/api/v5/repos/Lysssyo/DataofPersonalPage/contents/"+this.markdownID+".md?access_token=92843fa7206d85719b3f23d70f1a0a9a&ref="+this.BranchParam)
            .then(resp => {
                console.log("这是传递进then的参数："+this.markdownID)
                console.log("这是传递进then的参数的BranchParam："+this.BranchParam)
                console.log("https://gitee.com/api/v5/repos/Lysssyo/DataofPersonalPage/contents/"+this.markdownID+".md?access_token=92843fa7206d85719b3f23d70f1a0a9a&ref="+this.BranchParam)
                console.log("这个应该是md文件"+resp.data.content)
                const decodedMarkdownContent = atob(resp.data.content); //响应数据赋值给数据模型
                const utf8DecodedMarkdownContent= decodeURIComponent(escape(decodedMarkdownContent));
                this.markdownContent = utf8DecodedMarkdownContent.replace(/!\[.*?\]\((.*?)\)|<img src="(.*?)"(.*?)>/g, (match, p1, p2, p3) => {
                    console.log("匹配成功")
                    if (p1) {
                        return `<img src='http://gitee.com/lysssyo/WXMiniProgramPic/raw/main/${p1}'/>`;
                    } else {
                        return `<img src='http://gitee.com/lysssyo/WXMiniProgramPic/raw/main/${p2}' ${p3}>`;
                    }
                });
                console.log(this.markdownContent);
            });

    }
};
</script>
  